# Build your own Custom Indicator
import pandas as pd

# The data is already loaded into 'df'
# columns: Date, Open, High, Low, Close, Volume

# 1. Prepare Data
# Convert Date to Datetime for timestamp extraction if needed
# The backend already removes the space from '20250101 170000' -> '20250101170000'
df['Datetime'] = pd.to_datetime(df['Date'].astype(str), format='%Y%m%d%H%M%S')

# 2. Calculate Indicators
# Example: Bollinger Bands
window = 20
std_dev = 2.0

df['SMA'] = df['Close'].rolling(window=window).mean()
df['STD'] = df['Close'].rolling(window=window).std()
df['Upper'] = df['SMA'] + (df['STD'] * std_dev)
df['Lower'] = df['SMA'] - (df['STD'] * std_dev)

# 3. Export Indicators
# Define the 'indicators' list. Each item is a dictionary.
indicators = []

# Add SMA (Center Line)
indicators.append({
    "name": "SMA",
    "type": "line",
    "color": "#2962FF", # Blue
    "data": [
        {
            "time": int(df['Datetime'].iloc[i].timestamp()), 
            "value": float(df['SMA'].iloc[i])
        }
        for i in range(window, len(df))
        if not pd.isna(df['SMA'].iloc[i])
    ]
})

# Add Upper Band
indicators.append({
    "name": "Upper Band",
    "type": "line",
    "color": "#00E676", # Green
    "data": [
        {
            "time": int(df['Datetime'].iloc[i].timestamp()), 
            "value": float(df['Upper'].iloc[i])
        }
        for i in range(window, len(df))
        if not pd.isna(df['Upper'].iloc[i])
    ]
})

# Add Lower Band
indicators.append({
    "name": "Lower Band",
    "type": "line",
    "color": "#FF5252", # Red
    "data": [
        {
            "time": int(df['Datetime'].iloc[i].timestamp()), 
            "value": float(df['Lower'].iloc[i])
        }
        for i in range(window, len(df))
        if not pd.isna(df['Lower'].iloc[i])
    ]
})

